#!/usr/bin/env python3
"""iq-ladder-battery.py — function-space quality battery for one GGUF.

Part of the Phase 0 gate for the IQ quantization ladder (see plan
"Say very little with very little"). Distortion is measured at the OUTPUT:
raw-completion prompts with expected continuations, same methodology as the
qspec/ADMITTED_MODELS admission bar. Item 1 is the Paris probe with a real
logit-margin capture via llama-server logprobs.

Usage:
  python3 iq-ladder-battery.py \
    --model /path/model.gguf \
    --server /path/llama-server \
    --port 8931 \
    --out /path/report.json

Exit code 0 if the server ran and a report was written (pass/fail thresholds
are a HUMAN decision at the ladder's decision point; Paris rank-0 failure is
still flagged prominently in the report). Only infrastructure failures exit
nonzero.
"""

import argparse
import json
import math
import subprocess
import sys
import time
import urllib.error
import urllib.request

# Raw completions (not chat-templated) — consistent with the existing
# qspec/Paris admission methodology. `expect` = any-match, case-insensitive
# substrings of the first `n_predict` generated tokens.
BATTERY = [
    {"id": "paris", "prompt": "The capital of France is", "expect": ["paris"], "margin": True},
    {"id": "tokyo", "prompt": "The capital of Japan is", "expect": ["tokyo"]},
    {"id": "arith-add", "prompt": "2 + 2 =", "expect": ["4"]},
    {"id": "gold", "prompt": "The chemical symbol for gold is", "expect": ["au"]},
    {"id": "water", "prompt": "Water is composed of hydrogen and", "expect": ["oxygen"]},
    {"id": "hot-cold", "prompt": "The opposite of hot is", "expect": ["cold"]},
    {"id": "earth", "prompt": "The third planet from the sun is", "expect": ["earth"]},
    {"id": "juliet", "prompt": "William Shakespeare wrote the tragedy of Romeo and", "expect": ["juliet"]},
    {"id": "sqrt64", "prompt": "The square root of 64 is", "expect": ["8", "eight"]},
    {"id": "py-print", "prompt": "In Python, to print text to the console you call the function", "expect": ["print"]},
    {"id": "pacific", "prompt": "The largest ocean on Earth is the", "expect": ["pacific"]},
    {"id": "dna", "prompt": "DNA stands for deoxyribonucleic", "expect": ["acid"]},
    {"id": "light", "prompt": "The speed of light is approximately 300,000 kilometers per", "expect": ["second"]},
    {"id": "triangle", "prompt": "A triangle has exactly", "expect": ["three", "3"]},
    {"id": "austen", "prompt": "The author of 'Pride and Prejudice' is Jane", "expect": ["austen"]},
    {"id": "9x3", "prompt": "Nine times three equals", "expect": ["twenty-seven", "27"]},
    {"id": "freeze", "prompt": "The freezing point of water in Celsius is", "expect": ["0", "zero"]},
    {"id": "went", "prompt": "The past tense of 'go' is", "expect": ["went"]},
    {"id": "east", "prompt": "The sun rises in the", "expect": ["east"]},
    {"id": "kilobyte", "prompt": "One kilobyte is 1024", "expect": ["byte"]},
]


def http_json(url, payload=None, timeout=600):
    if payload is None:
        req = urllib.request.Request(url)
    else:
        req = urllib.request.Request(
            url,
            data=json.dumps(payload).encode("utf-8"),
            headers={"Content-Type": "application/json"},
        )
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        return json.loads(resp.read().decode("utf-8"))


def wait_healthy(port, proc, timeout_s):
    deadline = time.time() + timeout_s
    while time.time() < deadline:
        if proc.poll() is not None:
            raise RuntimeError(f"llama-server exited early with code {proc.returncode}")
        try:
            health = http_json(f"http://127.0.0.1:{port}/health", timeout=5)
            if health.get("status") == "ok":
                return
        except (urllib.error.URLError, ConnectionError, OSError):
            pass
        time.sleep(2)
    raise RuntimeError(f"llama-server not healthy after {timeout_s}s")


def run_item(port, item):
    payload = {
        "prompt": item["prompt"],
        "n_predict": 24,
        "temperature": 0.0,
        "cache_prompt": False,
    }
    if item.get("margin"):
        payload["n_probs"] = 10
    resp = http_json(f"http://127.0.0.1:{port}/completion", payload)
    content = resp.get("content", "")
    passed = any(e.lower() in content.lower() for e in item["expect"])
    result = {
        "id": item["id"],
        "prompt": item["prompt"],
        "expect": item["expect"],
        "generated": content[:200],
        "pass": passed,
    }
    if item.get("margin"):
        # llama-server returns per-token candidate logprobs under
        # completion_probabilities; schema has shifted across versions, so
        # handle both the `probs` and `top_logprobs`-style shapes defensively.
        margin = None
        top_token = None
        try:
            cp = resp.get("completion_probabilities") or []
            first = cp[0] if cp else {}
            cands = first.get("probs") or first.get("top_logprobs") or []
            norm = []
            for c in cands:
                tok = c.get("tok_str", c.get("token", ""))
                # `prob` is linear probability in older schema; `logprob` in newer.
                if "logprob" in c:
                    lp = float(c["logprob"])
                elif "prob" in c and float(c["prob"]) > 0:
                    lp = math.log(float(c["prob"]))
                else:
                    continue
                norm.append((tok, lp))
            norm.sort(key=lambda t: -t[1])
            if len(norm) >= 2:
                top_token = norm[0][0]
                margin = norm[0][1] - norm[1][1]
            elif len(norm) == 1:
                top_token = norm[0][0]
        except (KeyError, TypeError, ValueError, IndexError) as e:
            result["margin_error"] = f"{type(e).__name__}: {e}"
        result["top_token"] = top_token
        result["logprob_margin_top1_top2"] = margin
    return result


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--model", required=True)
    ap.add_argument("--server", required=True, help="path to llama-server binary")
    ap.add_argument("--port", type=int, default=8931)
    ap.add_argument("--threads", type=int, default=0, help="0 = llama-server default")
    ap.add_argument("--ctx", type=int, default=2048)
    ap.add_argument("--load-timeout", type=int, default=1800)
    ap.add_argument("--out", required=True)
    args = ap.parse_args()

    cmd = [
        args.server,
        "-m", args.model,
        "--port", str(args.port),
        "--host", "127.0.0.1",
        "-c", str(args.ctx),
        "--no-webui",
    ]
    if args.threads > 0:
        cmd += ["-t", str(args.threads)]

    print(f"[battery] starting llama-server: {' '.join(cmd)}", flush=True)
    log = open(args.out + ".server.log", "w")
    proc = subprocess.Popen(cmd, stdout=log, stderr=subprocess.STDOUT)
    report = {"model": args.model, "items": [], "battery_pass": 0, "battery_total": len(BATTERY)}
    try:
        wait_healthy(args.port, proc, args.load_timeout)
        print("[battery] server healthy, running battery", flush=True)
        for item in BATTERY:
            r = run_item(args.port, item)
            report["items"].append(r)
            status = "PASS" if r["pass"] else "FAIL"
            extra = ""
            if item.get("margin"):
                extra = f"  top={r.get('top_token')!r} margin={r.get('logprob_margin_top1_top2')}"
            print(f"[battery] {status} {item['id']}: {r['generated'][:60]!r}{extra}", flush=True)
        report["battery_pass"] = sum(1 for r in report["items"] if r["pass"])
        paris = next(r for r in report["items"] if r["id"] == "paris")
        report["paris_pass"] = paris["pass"]
        report["paris_margin"] = paris.get("logprob_margin_top1_top2")
    finally:
        proc.terminate()
        try:
            proc.wait(timeout=30)
        except subprocess.TimeoutExpired:
            proc.kill()
        log.close()

    with open(args.out, "w") as f:
        json.dump(report, f, indent=2)
    print(f"[battery] {report['battery_pass']}/{report['battery_total']} passed, "
          f"paris_pass={report.get('paris_pass')} margin={report.get('paris_margin')}", flush=True)
    print(f"[battery] report -> {args.out}", flush=True)


if __name__ == "__main__":
    main()
